var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"으하하, 정말 중령님 말씀대로 가끔은 이런 야외 캠핑도 제법 괜찮은 것 같습니다.","JPN":"ウハハ、中佐のおっしゃるとおり、たまにはこういう野外キャンプもなかなかいいですね。","ENG":"Hah hah, it's like you said, Lieutenant Colonel. It's nice to go camping outdoors from time to time like this.","TWN":"哈哈哈，如中校所說，偶爾來一次野外露營也不錯啊。"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"경관도 좋고, 먹을 것도 잔뜩 있으니, 천국이 따로 없네요.","JPN":"景色もいいし、食べ物もいっぱいあって、まさに天国です。","ENG":"The view's great and there's plenty to eat. This is paradise.","TWN":"不但風景好，還有一堆好吃的，簡直就是天堂啊。"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"그래, 오늘은 마음껏 먹고 마셔. 내일이 생각나지 않을 정도로 말이야.","JPN":"そうだな。今日は思いっきり食べて飲め。明日のことは考えなくていい。","ENG":"Yeah. Enjoy yourselves today. Like it's your last day on earth.","TWN":"沒錯，今天就盡情吃吧。把明天的事情拋在腦後，好好放鬆一下。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"이번 전술평가는 훌륭했어. 이제 델타 세븐도 평가부대가 아닌 정식부대다.","JPN":"今回の戦術は見事だった。これからデルタセブンも評価部隊じゃなく正式部隊だ。","ENG":"The tactical evaluation went superbly. Delta Seven is now officially a standing unit, not just some pilot program.","TWN":"這次的戰術評價非常出色。從今天開始我們第七三角洲部隊不再是評估部隊，而是一支正式部隊了。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"모두들 고생 많았어.","JPN":"皆、ご苦労だった。","ENG":"Good work, everyone.","TWN":"大夥都辛苦了。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"이게 다 저희가 훌륭한 지휘관님을 모시는 덕분이잖습니까?","JPN":"これもすべて立派な指揮官のおかげです。","ENG":"This is all thanks to our outstanding commander!","TWN":"這也都多虧了我們優秀的指揮官吧？"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"그나저나 지평선이 훤히 보이는 게 그야말로 장관이군요.","JPN":"それにしても、地平線がはっきり見えるのは本当に壮観ですね。","ENG":"By the way, the view of the horizon here is amazing.","TWN":"不過這裡居然能清楚看到地平線，真是絕景啊。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"중령님께선 이런 멋진 장소를 어떻게 아신 겁니까?","JPN":"中佐はこのような素敵な場所をどうやって見つけたんですか？","ENG":"How did you know about this place, sir?","TWN":"中將是怎麼找到這種好地方的？"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"......어릴 적 살던 집이랑 가까워서 자주 소풍을 왔었거든.","JPN":"……子供の頃住んでた家の近くだから、よく遊びに来てたんだ。","ENG":"I used to picnic here often when I was a kid. We lived nearby.","TWN":"……我小時候住的房子離這裡很近，所以經常會來這裡野餐。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"세상은 하루가 다르게 변해가지만 여기만은 추억 속 그대로인 점이 좋아.","JPN":"世の中すっかり変わってしまったが、ここだけは昔のままだから気に入っている。","ENG":"The world keeps changing so rapidly, but this place stays exactly as how I remember it. That's what I love about it.","TWN":"世界每天都在變，但只有這裡一直與我記憶中一模一樣，所以我很喜歡這裡。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"......이렇게 말하면 건방지단 소리 듣겠지만, 솔직히 말해 중령님이 부럽습니다.","JPN":"……こういうこと言うと生意気だと思われるかもしれませんが、正直中佐がうらやましいですね。","ENG":"If I may sir, honestly, I envy you.","TWN":"……雖然這麼說可能有些逾越，但說實話我很羡慕中將您。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"제 추억의 장소는 재작년에 침식지대로 선포가 돼서, 이젠 이터니움 실드 없인 들어갈 수 없는 곳이 되어버렸거든요.","JPN":"私の思い出の場所は一昨年に侵食地帯に指定されて、今はエタニウムシールドなしには入れなくなったんです。","ENG":"My childhood home was declared a Corrupted Area two years ago. I can't go there without an Eternium shield now.","TWN":"我記憶中的地方，去年被宣佈為侵蝕地區，現在沒有永恆之金護盾就無法進入了。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"유감이군.","JPN":"それは残念だ。","ENG":"Sorry to hear that.","TWN":"真是遺憾啊。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"하지만 그렇다고 해서, 소중한 걸 뺏긴 어린아이처럼 마냥 울고 있어서야 체면이 안 서지.","JPN":"しかし、だからといって大事な物を奪われた子供みたいにただ泣いているばかりじゃダメだろう。","ENG":"But we can't just cry about it like a kid who had his candy taken away.","TWN":"不過，我可不像小孩一樣，喜歡的東西被搶走就只會在那邊哭哭啼啼的。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"우리 힘으로 다시 되찾으면 되는 거야.","JPN":"我々の力で取り戻せばいいんだ。","ENG":"We'll take it back with our own hands.","TWN":"只要用我們的力量奪回那裡就行了。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"하하, 옳은 말씀이십니다! 침식체들 따위 우리 델타 세븐의 힘으로 다 몰아내버리자고요!","JPN":"ハハ、ごもっともです！　侵食体なんか、私たちデルタセブンの力で追い払ってやりましょうよ！","ENG":"Hah hah, you're spot on, sir! Let's drive out those C.O.s with the power of Delta Seven!","TWN":"哈哈，說得說錯！侵蝕體什麼的，就用我們第七三角洲部隊的力量把它們通通趕走吧！"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"중령님과 함께라면 불가능할 것도 없습니다! 암요!","JPN":"中佐とご一緒なら不可能なんてありません！　そう信じてます！","ENG":"Nothing's impossible with you, sir! Indeed!","TWN":"只要和中校大人在一起，我們無所不能！沒錯！"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"그야 당연하지.","JPN":"当然だ。","ENG":"Of course.","TWN":"當然了。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};